function terminalByTitle(title: string): HTMLElement {
  const terminal = screen
    .getAllByTestId("agent-xterm")
    .find((current) => current.textContent === title);
  if (!terminal) {
    throw new Error(`Expected ${title} agent terminal to be rendered.`);
  }
  return terminal;
}

