                        className="kerminal-pressable kerminal-focus-ring flex w-full min-w-0 items-start gap-2 rounded-xl px-2 py-2 text-left transition hover:bg-[var(--surface-hover)]"
                        disabled={rebindBusyTarget !== null}
                        key={targetKey}
